/**
 * Enables/disables a button based on Username input validity.
 * @param {string} inputId - ID of the Username input field.
 * @param {string} buttonId - ID of the button to enable/disable.
 */
const toggleButtonState = (inputId, buttonId) => {
    const inputField = document.getElementById(inputId);
    const button = document.getElementById(buttonId);

    if (!inputField || !button) {
        console.log(`Element with ID ${inputId} or ${buttonId} not found.`);
        return;
    }

    // Helper function to explicitly evaluate and set the disabled state
    const evaluateButtonState = () => {
        button.disabled = inputField.value.trim().length === 0;
    };

    // 1. Check immediately on script execution
    evaluateButtonState();

    // 2. Delayed checks: Give DaVinci time to asynchronously pre-populate the field
    setTimeout(evaluateButtonState, 150);
    setTimeout(evaluateButtonState, 500); // A secondary fallback for slow network rendering

    // 3. Bind multiple events to catch all types of user or browser input
    ['input', 'keyup', 'change'].forEach(eventType => {
        inputField.addEventListener(eventType, evaluateButtonState);
    });
};


